# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)

# Configuration
SECRET_KEY = os.environ.get('SECRET_KEY', secrets.token_hex(32))
JWT_EXPIRATION_HOURS = 24
NONCE_EXPIRATION_SECONDS = 300  # 5 minutes

# In-memory storage (use Redis or database in production)
nonces = {}
authenticated_sessions = {}

w3 = Web3()


def cleanup_expired_nonces():
    """Remove expired nonces"""
    current_time = time.time()
    expired = [addr for addr, data in nonces.items() 
               if current_time - data['timestamp'] > NONCE_EXPIRATION_SECONDS]
    for addr in expired:
        del nonces[addr]


def generate_nonce():
    """Generate a random nonce for authentication"""
    return secrets.token_hex(16)


def create_auth_message(address, nonce):
    """Create a standardized authentication message"""
    return f"Sign this message to authenticate with your wallet:\n\nAddress: {address}\nNonce: {nonce}\n\nThis request will expire in 5 minutes."


def verify_signature(message, signature, expected_address):
    """Verify that the signature matches the expected address"""
    try:
        # Encode the message using EIP-191
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def generate_jwt_token(address):
    """Generate JWT token for authenticated session"""
    payload = {
        'address': address.lower(),
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS),
        'iat': datetime.utcnow()
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm='HS256')
    return token


def verify_jwt_token(token):
    """Verify JWT token and return address"""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return payload.get('address')
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    """Generate and return a nonce for wallet authentication"""
    cleanup_expired_nonces()
    
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address format
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address to checksum format
    address = w3.to_checksum_address(address)
    
    # Generate nonce
    nonce = generate_nonce()
    
    # Store nonce with timestamp
    nonces[address] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    # Create the message to be signed
    message = create_auth_message(address, nonce)
    
    return jsonify({
        'nonce': nonce,
        'message': message,
        'address': address
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature_endpoint():
    """Verify signature and authenticate user"""
    cleanup_expired_nonces()
    
    data = request.get_json()
    
    # Validate required fields
    required_fields = ['address', 'signature', 'message']
    if not data or not all(field in data for field in required_fields):
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate Ethereum address format
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address
    address = w3.to_checksum_address(address)
    
    # Check if nonce exists for this address
    if address not in nonces:
        return jsonify({'error': 'No nonce found for this address. Please request a new nonce.'}), 401
    
    stored_data = nonces[address]
    
    # Check if nonce has expired
    if time.time() - stored_data['timestamp'] > NONCE_EXPIRATION_SECONDS:
        del nonces[address]
        return jsonify({'error': 'Nonce has expired. Please request a new nonce.'}), 401
    
    # Verify the message contains the correct nonce
    expected_message = create_auth_message(address, stored_data['nonce'])
    if message != expected_message:
        return jsonify({'error': 'Message does not match expected format'}), 401
    
    # Verify signature
    if not verify_signature(message, signature, address):
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Authentication successful - remove used nonce
    del nonces[address]
    
    # Generate JWT token
    token = generate_jwt_token(address)
    
    # Store session
    authenticated_sessions[address.lower()] = {
        'token': token,
        'authenticated_at': datetime.utcnow().isoformat()
    }
    
    return jsonify({
        'success': True,
        'address': address,
        'token': token,
        'message': 'Authentication successful'
    }), 200


@app.route('/api/auth/validate', methods=['POST'])
def validate_token():
    """Validate JWT token"""
    data = request.get_json()
    
    if not data or 'token' not in data:
        # Try to get token from Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header and auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
        else:
            return jsonify({'error': 'Token is required'}), 400
    else:
        token = data['token']
    
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token', 'valid': False}), 401
    
    return jsonify({
        'valid': True,
        'address': address
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
def logout():
    """Logout and invalidate session"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Authorization token required'}), 400
    
    token = auth_header.split(' ')[1]
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid token'}), 401
    
    # Remove session
    if address in authenticated_sessions:
        del authenticated_sessions[address]
    
    return jsonify({'success': True, 'message': 'Logged out successfully'}), 200


@app.route('/api/protected/profile', methods=['GET'])
def get_profile():
    """Example protected endpoint"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Authorization token required'}), 401
    
    token = auth_header.split(' ')[1]
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    # Return user profile data
    return jsonify({
        'address': address,
        'authenticated': True,
        'session_info': authenticated_sessions.get(address, {})
    }), 200


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({
        'status': 'healthy',
        'service': 'Web3 Authentication Service',
        'active_nonces': len(nonces),
        'active_sessions': len(authenticated_sessions)
    }), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)